code.C:
#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        if (n % m == 0) printf("0\n");
        else printf("%d\n", m - (n % m));
    }
    return 0;
}

