code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
        i++;
    } else {
        let input = line.split(' ').map(num => parseInt(num));
        let n = input[0];
        let m = input[1];
        if (n % m == 0) console.log(0);
        else console.log(m - (n % m));
        i++;
        if (i > t) readline.close();
    }
});

